import{walkUp}from"walk-up-path";import{resolve}from"node:path";import{stat,readFile}from"node:fs/promises";import{statSync,readFileSync}from"node:fs";async function fileExists(t){try{return(await stat(t)).isFile()}catch(t){return!1}}function fileExistsSync(t){try{return statSync(t).isFile()}catch(t){return!1}}export async function findPackagePath(t){for(const n of walkUp(t)){const t=resolve(n,"package.json");if(await fileExists(t))return t}return null}export async function findPackage(t){const n=await findPackagePath(t);if(!n)return null;try{const t=await readFile(n,{encoding:"utf8"});return JSON.parse(t)}catch(t){return null}}export function findPackagePathSync(t){for(const n of walkUp(t)){const t=resolve(n,"package.json");if(fileExistsSync(t))return t}return null}export function findPackageSync(t){const n=findPackagePathSync(t);if(!n)return null;try{const t=readFileSync(n,{encoding:"utf8"});return JSON.parse(t)}catch(t){return null}}